import { useParams } from "react-router-dom";
import { useState } from "react";

export default function IncidentDetail() {
  const { id } = useParams();

  const [form, setForm] = useState({
    start: "",
    end: "",
    rootCause: "",
    fix: "",
    prevention: ""
  });

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    await fetch(`http://localhost:8000/close/${id}`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify(form)
    });

    alert("Incident Closed!");
  };

  return (
    <div style={{ padding: "20px" }}>
      <h2>Incident {id}</h2>

      <form onSubmit={handleSubmit}>
        <input name="start" placeholder="Start Time" onChange={handleChange} /><br />
        <input name="end" placeholder="End Time" onChange={handleChange} /><br />
        <input name="rootCause" placeholder="Root Cause" onChange={handleChange} /><br />
        <input name="fix" placeholder="Fix" onChange={handleChange} /><br />
        <input name="prevention" placeholder="Prevention" onChange={handleChange} /><br />

        <button type="submit">Close Incident</button>
      </form>
    </div>
  );
}
